98	export function claim(
99	  incident: { damages: Array<Damage> },
100	  policy: { items: Array<Item> },
101	): number {
102	  const totals = incident.damages.reduce(
103	    (acc, damage) => {
104	      const policyItem = policy.items.find((item) => item.type === damage.itemType);
105	      return isDragonMaterial(policyItem)
106	        ? { ...acc, dragon: acc.dragon + damage.amount }
107	        : { ...acc, other: acc.other + reimbursableAmount(damage, policyItem) };
108	    },
109	    { dragon: 0, other: 0 },
110	  );
111	  return totals.dragon + Math.max(0, totals.other - DEDUCTIBLE);
112	}
