type QuoteStep = { op: "quote"; items: Array<Item> };
type ScenarioStep = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<ScenarioStep> };

export function runScenario(scenario: Scenario): { results: Array<{ premium: number }> } {
  const results: Array<{ premium: number }> = [];
  let previousQuotes = 0;
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const premium = quote({
        items: step.items,
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        previousQuotes,
      });
      results.push({ premium });
      previousQuotes += 1;
    }
  }
  return { results };
}
